SELECT DISTINCT ?dataset ?datasetName ?siteName ?latitude ?longitude ?resolution ?resolutionUnits ?minAge ?maxAge
WHERE {
  # Get datasets
  ?dataset a le:Dataset ;
           rdfs:label ?datasetName ;
           le:hasLocation ?location ;
           le:hasArchiveType arch:Coral ;
           le:hasPaleoData ?paleoData .

  # Get location information
